func extractSourceSample(n ast.Node, src []byte) []byte {
	var sample []byte

	if nn := n.FirstChild(); nn != nil {
		var start, stop int
		for i := 0; i < nn.Lines().Len() && i < 2; i++ {
			line := nn.Lines().At(i)
			if i == 0 {
				start = line.Start
			}
			stop = line.Stop
		}

		sample = src[start:stop]
	}
	return sample
}
